// ---- Added recipes: a bread breakfast, two rice mains (green-gram ndengu and
// the Kikuyu lentil "kamande"), and a Kenyan egg curry. Registered into the
// Kenyan pools so they appear in plans, search and the diet filters.
Object.assign(recipes, {
  'bread-eggs-chai':{id:'bread-eggs-chai',name:'Bread, Eggs & Chai',cuisine:'Kenyan',region:'Nationwide',tagline:'Breakfast · shop bread, quick',cost:1.6,protein:16,timeMin:12,prep:3,ingredients:[{item:'White bread',qty:'3 slices'},{item:'Eggs',qty:'2'},{item:'Butter',qty:'1 tbsp'},{item:'Milk',qty:'1 cup'},{item:'Tea leaves',qty:'1 tsp'},{item:'Sugar',qty:'1 tsp'}],steps:['Simmer the milk with tea leaves and sugar for a few minutes, then strain into a mug — that’s your chai.','Fry the eggs in butter to your liking.','Butter the bread and serve alongside the eggs and hot chai.'],note:'The everyday Kenyan breakfast — buttered shop bread, fried eggs and a mug of spiced tea, on the table in minutes.',storage:'Best made fresh; brew the chai just before serving.'},
  'homemade-bread':{id:'homemade-bread',name:'Homemade Bread',cuisine:'',tagline:'Breakfast · bake from scratch',cost:1.2,protein:8,timeMin:55,prep:20,ingredients:[{item:'Flour',qty:'3 cups'},{item:'Yeast',qty:'2 tsp'},{item:'Sugar',qty:'1 tbsp'},{item:'Milk',qty:'1 cup'},{item:'Butter',qty:'2 tbsp'},{item:'Salt',qty:'1 tsp'}],steps:['Warm the milk, stir in the sugar and yeast, and leave until frothy — about 10 minutes.','Mix into the flour and salt with the softened butter, then knead to a smooth, springy dough.','Cover and let it rise until doubled (about an hour), knock it back, shape into a tin, and prove again for 30 minutes.','Bake at 200°C for 28–32 minutes until golden and hollow-sounding; cool before slicing.'],note:'A soft white sandwich loaf from scratch — most of the time is hands-off proving. Cheaper and better than shop bread.',storage:'Keeps 3 days wrapped at room temperature, or slice and freeze for up to a month.'},
  'rice-ndengu':{id:'rice-ndengu',name:'Rice & Ndengu (Green Grams)',cuisine:'Kenyan',region:'Nationwide',tagline:'Lunch · budget & meat-free',cost:2.3,protein:18,timeMin:35,prep:5,ingredients:[{item:'Rice',qty:'1 cup'},{item:'Green grams (ndengu)',qty:'1 cup'},{item:'Onion',qty:'1'},{item:'Tomato',qty:'2'},{item:'Coconut milk',qty:'¼ cup'},{item:'Garlic',qty:'2 cloves'}],steps:['Boil the green grams until soft — soak them ahead to speed this up.','Fry onion, garlic and tomato into a soft base, stir in the ndengu with a splash of coconut milk, and simmer thick.','Serve over steamed rice.'],note:'Creamy green-gram stew over rice — a hearty, protein-rich plate that costs next to nothing.',storage:'Keeps 3 days chilled; the stew thickens and tastes even better the next day.'},
  'rice-kamande':{id:'rice-kamande',name:'Rice & Kamande (Lentils)',cuisine:'Kenyan',region:'Kikuyu',tagline:'Lunch · Kikuyu comfort',cost:2.2,protein:18,timeMin:35,prep:5,ingredients:[{item:'Rice',qty:'1 cup'},{item:'Lentils (kamande)',qty:'1 cup'},{item:'Onion',qty:'1'},{item:'Tomato',qty:'2'},{item:'Carrot',qty:'1'},{item:'Garlic',qty:'2 cloves'}],steps:['Boil the lentils with a little salt until tender.','Fry onion, garlic, grated carrot and tomato into a rich base, fold the lentils through, and simmer to thicken.','Serve over steamed rice.'],note:'Kamande — stewed lentils — over rice is a Kikuyu comfort classic: earthy, filling and gentle on the pocket.',storage:'Keeps 3–4 days chilled and freezes well.'},
  'egg-curry':{id:'egg-curry',name:'Egg Curry & Rice',cuisine:'Kenyan',region:'Coastal',tagline:'Dinner · rich & saucy',cost:2.6,protein:20,timeMin:30,prep:5,ingredients:[{item:'Eggs',qty:'3'},{item:'Rice',qty:'1 cup'},{item:'Onion',qty:'1'},{item:'Tomato',qty:'2'},{item:'Coconut milk',qty:'½ cup'},{item:'Curry powder',qty:'1 tbsp'},{item:'Garlic',qty:'2 cloves'},{item:'Ginger',qty:'thumb'}],steps:['Hard-boil the eggs, peel them, and lightly fry them whole so they take on a little colour.','Cook onion, garlic and ginger down, add tomato and curry powder, then loosen with coconut milk into a glossy sauce.','Simmer the eggs in the sauce for a few minutes and serve over rice.'],note:'A Kenyan favourite — whole eggs simmered in a spiced coconut-tomato curry, spooned over rice.',storage:'Keeps 2–3 days chilled; add a splash of water when reheating.'},
});
