// ---- More Kenyan staples: a boiled-egg & avocado breakfast, a sausage fry-up,
// street-food smokies, and two fish dishes.
Object.assign(recipes, {
  'eggs-avocado-tea':{id:'eggs-avocado-tea',name:'Boiled Eggs, Avocado & Tea',cuisine:'Kenyan',region:'Nationwide',tagline:'Breakfast · no-fuss & fresh',cost:2,protein:16,timeMin:12,prep:2,ingredients:[{item:'Eggs',qty:'2'},{item:'Avocado',qty:'1'},{item:'Milk',qty:'1 cup'},{item:'Tea leaves',qty:'1 tsp'},{item:'Sugar',qty:'1 tsp'},{item:'Salt',qty:'pinch'}],steps:['Boil the eggs for 8–9 minutes, then cool and peel.','Simmer the milk with tea leaves and sugar, and strain into a mug.','Halve the avocado, season with a pinch of salt, and serve with the eggs and hot tea.'],note:'A fresh, protein-rich start with no cooking skill required — creamy avocado, boiled eggs and a mug of chai.',storage:'Boil the eggs ahead and keep them peeled in the fridge for up to 3 days.'},
  'sausage-eggs':{id:'sausage-eggs',name:'Sausage & Fried Eggs',cuisine:'Kenyan',region:'Nationwide',tagline:'Breakfast · high-protein',cost:2.4,protein:26,timeMin:15,prep:3,ingredients:[{item:'Sausages',qty:'2'},{item:'Eggs',qty:'2'},{item:'Tomato',qty:'1'},{item:'Onion',qty:'½'},{item:'White bread',qty:'2 slices'}],steps:['Fry the sausages until browned all over.','Soften the onion and tomato in the same pan, then fry the eggs alongside.','Serve hot with bread.'],note:'A hearty, protein-packed fry-up — browned sausages, eggs and a quick tomato-onion, all in one pan.',storage:'Best fresh; sausages can be cooked ahead and reheated.'},
  'smokies-kachumbari':{id:'smokies-kachumbari',name:'Smokies & Kachumbari',cuisine:'Kenyan',region:'Nationwide',tagline:'Lunch · street-food classic',cost:2.2,protein:18,timeMin:15,prep:5,ingredients:[{item:'Smokies',qty:'3'},{item:'Tomato',qty:'2'},{item:'Red onion',qty:'1'},{item:'Chili',qty:'1'},{item:'Lemon',qty:'½'}],steps:['Warm or lightly fry the smokies until heated through.','Dice the tomato, red onion and chili, and dress with a squeeze of lemon and a pinch of salt — that’s kachumbari.','Serve the smokies with the fresh kachumbari on the side.'],note:'Kenya’s favourite street snack — smoky sausages with a sharp, fresh tomato-and-onion kachumbari.',storage:'Make the kachumbari fresh; it softens if it sits too long.'},
  'tilapia-ugali':{id:'tilapia-ugali',name:'Fried Tilapia & Ugali',cuisine:'Kenyan',region:'Luo',tagline:'Dinner · lake-fresh',cost:3,protein:32,timeMin:30,prep:8,ingredients:[{item:'Tilapia',qty:'1 whole'},{item:'Cornmeal (ugali)',qty:'1 cup'},{item:'Tomato',qty:'1'},{item:'Red onion',qty:'1'},{item:'Lemon',qty:'½'},{item:'Garlic',qty:'2 cloves'}],steps:['Score and season the tilapia, then shallow-fry until crisp and cooked through.','Whisk the cornmeal into boiling water, stirring until it stiffens into ugali.','Serve the fish with ugali and a fresh tomato-onion kachumbari.'],note:'A Lake Victoria classic — crisp whole tilapia with a stiff ugali and a sharp kachumbari.',storage:'Best eaten fresh; the fish loses its crispness on reheating.'},
  'fish-stew-rice':{id:'fish-stew-rice',name:'Fish Stew & Rice',cuisine:'Kenyan',region:'Nationwide',tagline:'Dinner · rich & saucy',cost:2.8,protein:28,timeMin:30,prep:6,ingredients:[{item:'Tilapia',qty:'1 fillet'},{item:'Rice',qty:'1 cup'},{item:'Tomato',qty:'2'},{item:'Onion',qty:'1'},{item:'Coconut milk',qty:'½ cup'},{item:'Garlic',qty:'2 cloves'}],steps:['Sear the fish briefly, then set it aside.','Cook the onion, garlic and tomato into a soft base, loosen with coconut milk, and simmer.','Slip the fish back in to finish cooking gently, and serve over steamed rice.'],note:'Tender fish in a coconut-tomato stew, spooned over rice — comforting and quick.',storage:'Keeps 2 days chilled; reheat gently so the fish stays intact.'},
});
